<?php
namespace App\Modules\Hr\Engagement\Actions;
use App\Modules\Hr\Core\Services\HrAuditService; use App\Modules\Hr\Core\Services\TenantContext; use App\Modules\Hr\Engagement\Models\HrSurvey; use Carbon\Carbon;
class CreateSurveyAction { public function __construct(private HrAuditService $audit){} public function execute(array $data):HrSurvey{abort_unless(auth()->user()?->hasHrPermission('hr.engagement.manage_surveys'),403);$questions=$data['questions']??[];abort_if(blank($data['title']??null)||!is_array($questions)||empty($questions),422);$ids=[];$enps=0;foreach($questions as $q){$id=trim((string)($q['id']??''));$type=$q['type']??'scale';abort_if($id===''||in_array($id,$ids,true)||blank($q['label']??null)||!in_array($type,['scale','enps','text'],true),422,'Anket soruları geçersiz.');$ids[]=$id;if($type==='enps')$enps++;}abort_if($enps>1,422,'Ankette yalnızca bir eNPS sorusu olabilir.');$start=Carbon::parse($data['starts_on']??null);$end=Carbon::parse($data['ends_on']??null);abort_if($end->lt($start),422,'Anket tarihleri geçersiz.');$survey=HrSurvey::create(['legal_entity_id'=>app(TenantContext::class)->getId(),'title'=>trim($data['title']),'description'=>$data['description']??null,'questions'=>$questions,'starts_on'=>$start,'ends_on'=>$end,'status'=>'draft','is_anonymous'=>(bool)($data['is_anonymous']??true),'minimum_report_count'=>max(3,(int)($data['minimum_report_count']??3)),'created_by'=>auth()->id()]);$this->audit->log('engagement_survey_created',$survey);return $survey;} public function transition(HrSurvey $survey,string $status):HrSurvey{abort_unless(auth()->user()?->hasHrPermission('hr.engagement.manage_surveys'),403);abort_unless($survey->legal_entity_id===app(TenantContext::class)->getId(),404);$allowed=['draft'=>'active','active'=>'closed'];abort_unless(($allowed[$survey->status]??null)===$status,422,'Geçersiz anket geçişi.');$survey->update(['status'=>$status]);$this->audit->log('engagement_survey_transitioned',$survey,null,['status'=>$status]);return $survey->fresh();} }
